THOUGHT: I will patch InstCombineSelect.cpp to add poison-element checks before performing the two uadd.sat folds that use m_Not, preventing the miscompilation. Then I will submit the patch.

```bash
python3 - <<'PY'
import pathlib, re
path = pathlib.Path("llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp")
text = path.read_text()

# Patch first fold (~X u< Y) ? -1 : (X + Y)
pattern1 = re.compile(r'(// \(~X u< Y\) \? -1 : \(X \+ Y\) --> uadd\.sat\(X, Y\)
\s*// \(~X u< Y\) \? -1 : \(Y \+ X\) --> uadd\.sat\(X, Y\)
\s*return Builder\.CreateBinaryIntrinsic\(Intrinsic::uadd_sat, X, Y\);)')
def repl1(m):
    return m.group(1).replace(
        'return Builder.CreateBinaryIntrinsic(Intrinsic::uadd_sat, X, Y);',
        '{
      // Avoid folding if the NOT is an xor with a poison-containing constant.
      auto HasPoisonNot = [](Value *V) {
        if (!V) return false;
        if (auto *BO = dyn_cast<BinaryOperator>(V)) {
          if (BO->getOpcode() == Instruction::Xor)
            if (auto *C = dyn_cast<Constant>(BO->getOperand(1)))
              return C->containsPoisonElement();
        } else if (auto *CE = dyn_cast<ConstantExpr>(V)) {
          if (CE->getOpcode() == Instruction::Xor)
            if (auto *C = dyn_cast<Constant>(CE->getOperand(1)))
              return C->containsPoisonElement();
        }
        return false;
      };
      if (HasPoisonNot(Cmp0))
        return nullptr;
      return Builder.CreateBinaryIntrinsic(Intrinsic::uadd_sat, X, Y);
    }')
text_new = pattern1.sub(repl1, text)

# Patch second fold (X u< Y) ? -1 : (~X + Y)
pattern2 = re.compile(r'(// \(X u< Y\) \? -1 : \(~X \+ Y\) --> uadd\.sat\(~X, Y\)
\s*// \(X u< Y\) \? -1 : \(Y \+ ~X\) --> uadd\.sat\(Y, ~X\)
\s*BinaryOperator \*BO = cast<BinaryOperator>\(FVal\);
\s*return Builder\.CreateBinaryIntrinsic\(
\s*Intrinsic::uadd_sat, BO->getOperand\(0\), BO->getOperand\(1\)\);)', re.MULTILINE)
def repl2(m):
    return m.group(1).replace(
        'return Builder.CreateBinaryIntrinsic(
        Intrinsic::uadd_sat, BO->getOperand(0), BO->getOperand(1));',
        '{
    // Avoid folding if either operand is a NOT encoded as xor with poison.
    auto HasPoisonNot = [](Value *V) {
      if (!V) return False;
      if (auto *BO2 = dyn_cast<BinaryOperator>(V)) {
        if (BO2->getOpcode() == Instruction::Xor)
          if (auto *C = dyn_cast<Constant>(BO2->getOperand(1)))
            return C->containsPoisonElement();
      } else if (auto *CE2 = dyn_cast<ConstantExpr>(V)) {
        if (CE2->getOpcode() == Instruction::Xor)
          if (auto *C = dyn_cast<Constant>(CE2->getOperand(1)))
            return C->containsPoisonElement();
      }
      return False;
    };
    if (HasPoisonNot(BO->getOperand(0)) || HasPoisonNot(BO->getOperand(1)))
      return nullptr;
    return Builder.CreateBinaryIntrinsic(
        Intrinsic::uadd_sat, BO->getOperand(0), BO->getOperand(1));
  }')
# Fix capitalization of 'False' to 'false' (typo) after replacement.
text_new = pattern2.sub(repl2, text_new).replace('return False;', 'return false;')

if text_new == text:
    print("Patch did not apply; patterns not found.")
else:
    path.write_text(text_new)
    print("Patch applied.")
PY
&& submit-patch
```

